targets.expr:
max by (schedule,exported_namespace) (
  stork_migration_completion_timestamp_seconds{
    cluster=~"$cluster",
    status=~"Successful|PartialSuccess",
    schedule=~"$migrationschedule",
    schedule!="NA",
    exported_namespace=~"$namespace"
  }
) * 1000

(
  stork_migration_volumes{
    cluster=~"$cluster",
    exported_namespace=~"$namespace",
    schedule=~"$migrationschedule",
    state="migrated"
  }
  /
  stork_migration_volumes{
    cluster=~"$cluster",
    exported_namespace=~"$namespace",
    schedule=~"$migrationschedule",
    state="planned"
  }
) * 100

(
  stork_migration_resources{
    cluster=~"$cluster",
    exported_namespace=~"$namespace",
    schedule=~"$migrationschedule",
    state="migrated"
  }
  /
  stork_migration_resources{
    cluster=~"$cluster",
    exported_namespace=~"$namespace",
    schedule=~"$migrationschedule",
    state="planned"
  }
) * 100

max by (cluster, namespace, type) (
  stork_action_completion_timestamp_seconds{
    cluster=~"$cluster",
    exported_namespace=~"$namespace",
  }
) * 1000
